bool helper(int index, int currentSum, vector<int>& nums, int k) {
    // If target sum is reached
    if (currentSum == k) return true;

    // If end of array is reached or sum exceeds k
    if (index == nums.size() || currentSum > k) return false;

    // Include current element
    if (helper(index + 1, currentSum + nums[index], nums, k))
        return true;

    // Exclude current element
    if (helper(index + 1, currentSum, nums, k))
        return true;

    return false;
}

bool existsSubsequence(vector<int>& nums, int n, int k) {
    return helper(0, 0, nums, k);
}

