class Solution {
    private static boolean helper(int index, int currentSum, int[] nums, int k) {
        // If target sum is reached
        if (currentSum == k) {
            return true;
        }

        // If end of array is reached or sum exceeds k
        if (index == nums.length || currentSum > k) {
            return false;
        }

        // Include current element
        if (helper(index + 1, currentSum + nums[index], nums, k)) {
            return true;
        }

        // Exclude current element
        if (helper(index + 1, currentSum, nums, k)) {
            return true;
        }

        return false;
    }

    public  boolean existsSubsequence(int[] nums, int n, int k) {
        return helper(0, 0, nums, k);
    }
}

